def assign_teams_to_pots(teams, pot_sizes=[8, 8, 8, 8]):
    # teams is a list of tuples: (team_name, ranking)
    # Sort teams by ranking (ascending)
    sorted_teams = sorted(teams, key=lambda x: x[1])
    pots = {f'Pot {i+1}': [] for i in range(4)}

    # Assign teams to pots based on ranking
    for i, team in enumerate(sorted_teams):
        if i < pot_sizes[0]:
            pots['Pot 1'].append(team[0])
        elif i < pot_sizes[0] + pot_sizes[1]:
            pots['Pot 2'].append(team[0])
        elif i < pot_sizes[0] + pot_sizes[1] + pot_sizes[2]:
            pots['Pot 3'].append(team[0])
        else:
            pots['Pot 4'].append(team[0])

    return pots

# Example usage:
teams = [
    ('Qatar', 51), ('Brazil', 1), ('Belgium', 2), ('France', 3),
    ('Argentina', 4), ('England', 5), ('Spain', 7), ('Portugal', 8),
    ('Netherlands', 10), ('Italy', 6), ('Mexico', 9), ('USA', 15),
    ('Croatia', 12), ('Germany', 11), ('Uruguay', 13), ('Switzerland', 14)
]
print(assign_teams_to_pots(teams))
